export function exportRows(rows: object[], format: Format = 'csv'): string {
  if (format === 'json') return JSON.stringify(rows, null, 2);
  const keys = Object.keys(rows[0] ?? {});
  return [keys.join(','), ...rows.map((r) => keys.map((k) => r[k]).join(','))].join('\n');
}

