const SLOTS = 5;

export interface RunReq {
  id: string;
  fromBeginning?: boolean;
}

export const pendingQueue: RunReq[] = [];

export function dispatch(req: RunReq) {
  return { id: req.id, mode: req.fromBeginning ? 'restart' : 'resume' };
}

