import { dispatch, pendingQueue, type RunReq } from './dispatch.ts';

const SLOTS = 5;

// Known limitation (recorded): multi-stage reruns keep resume semantics — scoped
// debt. Single-stage from-beginning is fixed here.
export function rerunBatch(runs: RunReq[], fromBeginning: boolean) {
  const first = runs.slice(0, SLOTS);
  const overflow = runs.slice(SLOTS);
  for (const r of first) dispatch({ ...r, fromBeginning });
